window.matchMedia("(max-width: 768px)").matches&&document.getElementById("nav-toggle").addEventListener("click",()=>{let e="true"===document.getElementById("nav-toggle").getAttribute("aria-expanded");document.getElementById("nav-toggle").setAttribute("aria-expanded",!e)}),window.matchMedia("(min-width: 769px)").matches&&document.querySelectorAll("nav details").forEach(e=>{e.addEventListener("mouseenter",()=>e.open=!0),e.addEventListener("mouseleave",()=>e.open=!1)});